class Solution {
    public String minimizeStringValue(String s) {
        int[] count = new int[26];
        char[] chars = s.toCharArray();
        for (int i = 0; i < chars.length; i++) {
            if (chars[i] == '?') {
                int min = 0;
                for (int j = 0; j < 26; j++) {
                    if (count[j] < count[min]) {
                        min = j;
                    }
                }
                chars[i] = (char) ('a' + min);
                count[min]++;
            } else {
                count[chars[i] - 'a']++;
            }
        }
        return new String(chars);
    }
}
```
